import{_ as e,o as t,c as l,ai as r}from"./chunks/framework.DjxHwWNk.js";const m=JSON.parse('{"title":"Дворец молодёжи","description":"Одна из главных концертных площадок Екатеринбурга и место легендарных фестивалей Свердловского рок-клуба.","frontmatter":{"title":"Дворец молодёжи","description":"Одна из главных концертных площадок Екатеринбурга и место легендарных фестивалей Свердловского рок-клуба.","outline":"deep"},"headers":[],"relativePath":"places/dvorets-molodezhi.md","filePath":"places/dvorets-molodezhi.md"}'),d={name:"places/dvorets-molodezhi.md"};function s(i,a,o,h,n,p){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="дворец-молодежи" tabindex="-1">Дворец молодёжи <a class="header-anchor" href="#дворец-молодежи" aria-label="Permalink to “Дворец молодёжи”">​</a></h1><p><strong>Дворец молодёжи</strong> — одна из ключевых концертных площадок в истории уральского рока. Здесь проходили крупные фестивали Свердловского рок-клуба, выступали главные группы сцены, а позднее площадка стала связана с фестивалем «Старый Новый Рок».</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, пр. Ленина, 1</li><li><strong>Период ключевого значения:</strong> 1980-е годы — настоящее время</li><li><strong>Главная роль:</strong> крупная концертная площадка Свердловска и Екатеринбурга</li><li><strong>Связанные группы:</strong> «Наутилус Помпилиус», «Агата Кристи», «Чайф», «Настя», «Апрельский марш», «Отражение», «Смысловые Галлюцинации», «Сансара», «Обе-Рек»</li><li><strong>Статус сегодня:</strong> действующая концертная площадка</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>Дворец молодёжи стал одной из площадок, где уральский рок окончательно вышел за пределы андеграунда. Если ДК имени Свердлова был символической колыбелью Свердловского рок-клуба, то Дворец молодёжи показал масштаб движения: большие залы, массовая аудитория, фестивальная атмосфера и участие главных групп СРК.</p><p>Особое значение имеют третий и четвёртый фестивали Свердловского рок-клуба, прошедшие здесь 16 октября 1988 года. Эти события стали важной точкой в истории сцены: рок-культура переставала быть полуподпольным явлением и превращалась в заметную часть городской и музыкальной жизни.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Здание Дворца молодёжи было построено в 1970-х годах как современный многофункциональный комплекс для городских мероприятий, концертов и фестивалей. Благодаря вместительному большому залу и хорошей сцене оно быстро стало одной из главных концертных площадок Свердловска.</p><p>В истории уральского рока Дворец молодёжи занял особое место как место проведения легендарных третьего и четвёртого фестивалей Свердловского рок-клуба. Они состоялись 16 октября 1988 года и стали поворотным моментом для всей сцены. На сцене выступили ключевые коллективы СРК: «Наутилус Помпилиус», «Агата Кристи», «Чайф», «Настя», «Апрельский марш», «Отражение» и другие группы.</p><p>Зал был переполнен, а атмосфера фестивалей запомнилась как электризующая. Для многих зрителей и музыкантов эти концерты стали подтверждением того, что свердловский рок уже вышел на уровень крупных городских событий и способен собирать массовую аудиторию.</p><p>В последующие годы Дворец молодёжи сохранил связь с рок-культурой. С 2000 года он стал одной из постоянных площадок фестиваля <strong>«Старый Новый Рок»</strong>, который давал возможность заявить о себе новым поколениям уральских групп. Здесь выступали «Смысловые Галлюцинации», «Сансара», «Обе-Рек» и другие коллективы.</p><p>В 1990-е и 2000-е годы здание неоднократно реконструировалось, но сохранило статус одной из главных концертных площадок Екатеринбурга.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, пр. Ленина, 1.</p><p>Дворец молодёжи расположен в центральной части города и хорошо подходит для включения в туристические маршруты по рок-местам Екатеринбурга.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/evgeny-gorenburg.html">Евгений Горенбург</a></td><td>Организатор фестивалей Свердловского рок-клуба и фестиваля «Старый Новый Рок»</td></tr><tr><td><a href="/Knowledge-Base/people/vyacheslav-butusov.html">Вячеслав Бутусов</a></td><td>Участник фестивалей 1988 года в составе «Наутилуса Помпилиус»</td></tr><tr><td><a href="/Knowledge-Base/people/vadim-samoilov.html">Вадим Самойлов</a></td><td>Участник фестивалей 1988 года в составе «Агаты Кристи»</td></tr><tr><td><a href="/Knowledge-Base/people/vladimir-shahrin.html">Владимир Шахрин</a></td><td>Участник фестивалей 1988 года в составе «Чайфа»</td></tr><tr><td><a href="/Knowledge-Base/people/nastya-poleva.html">Настя Полева</a></td><td>Участница фестивалей Свердловского рок-клуба</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><ul><li><a href="/Knowledge-Base/bands/nautilus-pompilius.html">Наутилус Помпилиус</a></li><li><a href="/Knowledge-Base/bands/agata-kristi.html">Агата Кристи</a></li><li><a href="/Knowledge-Base/bands/chaif.html">Чайф</a></li><li><a href="/Knowledge-Base/bands/nastya.html">Настя</a></li><li><a href="/Knowledge-Base/bands/aprelsky-marsh.html">Апрельский марш</a></li><li><a href="/Knowledge-Base/bands/otrazhenie.html">Отражение</a></li><li><a href="/Knowledge-Base/bands/smyslovye-gallyutsinatsii.html">Смысловые Галлюцинации</a></li><li><a href="/Knowledge-Base/bands/sansara.html">Сансара</a></li><li><a href="/Knowledge-Base/bands/obe-rek.html">Обе-Рек</a></li></ul><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня Дворец молодёжи остаётся действующей концертной площадкой и одной из востребованных культурных точек Екатеринбурга. Здесь проходят концерты, фестивали, городские мероприятия и крупные события.</p><p>Для истории уральского рока это место важно как пространство преемственности: здесь выступали легенды Свердловского рок-клуба, а позднее — новые поколения уральских музыкантов.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Перед посещением мероприятий стоит уточнять расписание на официальных ресурсах площадки: формат, билеты и доступность событий могут отличаться.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока Дворец молодёжи снова становится одной из ключевых сцен. Площадка связана с юбилейными концертами, реюнионами легендарных групп и программой фестиваля <strong>«Старый Новый Рок 2026»</strong>.</p><p>Здание также включается в туристические маршруты по рок-местам Екатеринбурга как место, где свердловская сцена вышла на большой концертный уровень.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Юбилейные концерты, посвящённые Году уральского рока</td></tr><tr><td>2026 год</td><td>Реюнионы и специальные выступления легендарных групп</td></tr><tr><td>2026 год</td><td>Торжественное открытие фестиваля «Старый Новый Рок 2026»</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>Дворец молодёжи удобно включать в маршрут по центральным рок-местам Екатеринбурга. Его можно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a></li><li><a href="/Knowledge-Base/places/school-2.html">Школа № 2</a></li><li><a href="/Knowledge-Base/places/bashlachev-house.html">Дом Александра Башлачёва</a></li></ul>',31)])])}const b=e(d,[["render",s]]);export{m as __pageData,b as default};
